/* ------------------------------------------------------------------ */
/*  Theme context — every component reads live config from here        */
/* ------------------------------------------------------------------ */
const ThemeContext = createContext(null);
function useTheme() {
  return useContext(ThemeContext);
}

function buildTheme(cfg, track) {
  const serif = { fontFamily: FONT_DISPLAY_OPTIONS.find((f) => f.id === cfg.fontDisplay)?.family || FONT_DISPLAY_OPTIONS[0].family };
  const sans = { fontFamily: FONT_BODY_OPTIONS.find((f) => f.id === cfg.fontBody)?.family || FONT_BODY_OPTIONS[0].family };
  const colors = { ...cfg.colors, ...(cfg.trackOverrides[track] || {}) };
  const bannerUrl = cfg.trackBanners[track] || "";

  function trackInfo(trackKey) {
    const accent = trackKey === "civil" ? cfg.colors.civilAccent : cfg.colors.militarAccent;
    return {
      key: trackKey,
      label: cfg.copy[trackKey].label,
      accent,
      accentSoft: mix(accent, "#ffffff", 0.85),
      accentDeep: mix(accent, "#000000", 0.35),
      eyebrow: cfg.copy[trackKey].eyebrow,
      headline: cfg.copy[trackKey].headline,
      paragraph: cfg.copy[trackKey].paragraph,
      icon: cfg.trackIcons[trackKey] || null,
      IconComponent: trackKey === "civil" ? Briefcase : Shield,
    };
  }

  function categoryMeta(catKey) {
    return {
      label: cfg.categoryLabels[catKey],
      noun: CATEGORY_NOUNS[catKey],
      emoji: cfg.icons[catKey] || null,
      IconComponent: CATEGORY_ICON_COMPONENTS[catKey],
    };
  }

  return { cfg, colors, bannerUrl, serif, sans, trackInfo, categoryMeta };
}

function isImageValue(v) {
  return typeof v === "string" && (v.startsWith("http") || v.startsWith("data:image"));
}

function CategoryIcon({ catKey, size = 20, style = {} }) {
  const { categoryMeta } = useTheme();
  const meta = categoryMeta(catKey);
  if (meta.emoji) {
    if (isImageValue(meta.emoji)) {
      return <img src={meta.emoji} alt={meta.label} style={{ height: size, width: size, objectFit: "contain", ...style }} />;
    }
    return (
      <span style={{ fontSize: size, lineHeight: 1, ...style }} role="img" aria-label={meta.label}>
        {meta.emoji}
      </span>
    );
  }
  const Icon = meta.IconComponent;
  return <Icon size={size} style={style} />;
}

function TrackIconGlyph({ trackKey, size = 14, style = {} }) {
  const { trackInfo } = useTheme();
  const t = trackInfo(trackKey);
  if (t.icon) {
    if (isImageValue(t.icon)) {
      return <img src={t.icon} alt={t.label} style={{ height: size, width: size, objectFit: "contain", ...style }} />;
    }
    return (
      <span style={{ fontSize: size, lineHeight: 1, ...style }} role="img" aria-label={t.label}>
        {t.icon}
      </span>
    );
  }
  const Icon = t.IconComponent;
  return <Icon size={size} style={style} />;
}

function uid() {
  return (crypto.randomUUID && crypto.randomUUID()) || `${Date.now()}-${Math.random().toString(16).slice(2)}`;
}
function formatDate(iso) {
  try {
    return new Date(iso).toLocaleDateString("es-ES", { day: "numeric", month: "long", year: "numeric" });
  } catch {
    return iso;
  }
}
function isRecent(iso) {
  return Date.now() - new Date(iso).getTime() < 7 * 24 * 60 * 60 * 1000;
}
