function CategoriesBlock({ exercises, setView, track }) {
  const { cfg, colors, serif, sans, trackInfo } = useTheme();
  const t = trackInfo(track);
  const trackExercises = useMemo(() => exercises.filter((e) => e.track === track), [exercises, track]);
  const counts = useMemo(() => {
    const c = { grammar: 0, listening: 0, reading: 0, writing: 0 };
    trackExercises.forEach((e) => (c[e.type] = (c[e.type] || 0) + 1));
    return c;
  }, [trackExercises]);

  return (
    <section className="max-w-6xl mx-auto px-6 pb-16">
      <div className="grid sm:grid-cols-2 md:grid-cols-4 gap-4">
        {CATEGORY_KEYS.map((key) => (
          <button
            key={key}
            onClick={() => setView({ name: key })}
            className="text-left p-5 border transition-shadow hover:shadow-md"
            style={{ borderColor: colors.line, backgroundColor: colors.card }}
          >
            <div className="mb-4">
              <CategoryIcon catKey={key} size={22} style={{ color: t.accent }} />
            </div>
            <div style={{ ...serif, color: colors.ink }} className="text-lg font-semibold mb-1">
              {cfg.categoryLabels[key]}
            </div>
            <div style={{ ...sans, color: "#5B6472" }} className="text-sm">
              {counts[key] || 0} {CATEGORY_NOUNS[key]}
              {(counts[key] || 0) === 1 ? "" : "s"} disponible{(counts[key] || 0) === 1 ? "" : "s"}
            </div>
          </button>
        ))}
      </div>
    </section>
  );
}

function StarRating({ rating, size = 14, color }) {
  return (
    <span style={{ color, lineHeight: 1 }} aria-label={`${rating} de 5 estrellas`}>
      {"★".repeat(rating)}
      <span style={{ opacity: 0.25 }}>{"★".repeat(5 - rating)}</span>
    </span>
  );
}

function ReviewsBlock({ reviews }) {
  const { cfg, colors, serif, sans } = useTheme();
  if (!reviews.length) return null;
  return (
    <section className="max-w-6xl mx-auto px-6 pb-16">
      <h2 style={{ ...serif, color: colors.ink }} className="text-xl font-semibold mb-4">
        Lo que dicen nuestros alumnos
      </h2>
      <div className="grid sm:grid-cols-2 md:grid-cols-3 gap-4">
        {reviews.map((r) => (
          <div key={r.id} className="p-4 border" style={{ borderColor: colors.line, backgroundColor: colors.card }}>
            <StarRating rating={r.rating} color="#D4A017" />
            <p style={{ ...sans, color: colors.ink }} className="text-sm mt-2 leading-relaxed">
              "{r.body}"
            </p>
            <p style={{ ...sans, color: "#5B6472" }} className="text-xs mt-3 font-semibold">
              — {r.authorName}
            </p>
          </div>
        ))}
      </div>
    </section>
  );
}

