function CategoryList({ type, exercises, materials, setView, focusId, track, submissions, currentUser }) {
  const { cfg, colors, serif, sans, trackInfo } = useTheme();
  const t = trackInfo(track);
  const list = useMemo(
    () => exercises.filter((e) => e.type === type && e.track === track),
    [exercises, type, track]
  );

  function priorFor(exerciseId) {
    if (!currentUser || !submissions) return null;
    return submissions.find((s) => s.userId === currentUser.id && s.exerciseId === exerciseId) || null;
  }

  return (
    <div className="max-w-4xl mx-auto px-6 py-12">
      <div className="flex items-center gap-3 mb-2">
        <CategoryIcon catKey={type} size={22} style={{ color: t.accent }} />
        <h2 style={{ ...serif, color: colors.ink }} className="text-2xl font-semibold">
          {cfg.categoryLabels[type]}
        </h2>
        <span className="text-[10px] font-semibold uppercase px-2 py-1 rounded-sm" style={{ backgroundColor: t.accentSoft, color: t.accentDeep, ...sans }}>
          {t.label}
        </span>
      </div>
      <GoldRule accent={t.accent} className="mb-8 max-w-xs" />

      <MaterialsSection materials={materials} type={type} track={track} />

      {list.length === 0 ? (
        <p style={{ ...sans, color: "#5B6472" }}>
          Todavía no hay contenido en esta sección para el área {t.label.toLowerCase()}. Añádelo desde el panel de administración.
        </p>
      ) : (
        <ul className="space-y-3">
          {list.map((e) => {
            const prior = priorFor(e.id);
            return (
            <li key={e.id}>
              <button
                onClick={() => setView({ name: "detail", id: e.id, from: type })}
                className="w-full flex items-center justify-between gap-4 p-4 border text-left hover:shadow-sm transition-shadow"
                style={{ borderColor: e.id === focusId ? t.accent : colors.line, backgroundColor: colors.card }}
              >
                <div>
                  <div style={{ ...sans, color: colors.ink }} className="font-medium">
                    {e.title}
                  </div>
                  <div style={{ ...sans, color: "#5B6472" }} className="text-xs flex items-center gap-2 mt-1">
                    <Clock size={12} /> {formatDate(e.dateAdded)}
                    {isRecent(e.dateAdded) && (
                      <span className="ml-1 px-1.5 py-0.5 rounded-sm text-[10px] font-semibold uppercase" style={{ backgroundColor: t.accentSoft, color: t.accentDeep }}>
                        Nuevo
                      </span>
                    )}
                    {prior && (
                      <span className="ml-1 px-1.5 py-0.5 rounded-sm text-[10px] font-semibold uppercase" style={{ backgroundColor: mix(colors.success, "#ffffff", 0.85), color: colors.success }}>
                        Hecho: {prior.score}/{prior.total}
                      </span>
                    )}
                  </div>
                </div>
                <LevelBadge level={e.level} accent={t.accent} />
              </button>
            </li>
          );})}
        </ul>
      )}
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Exercise detail                                                     */
/* ------------------------------------------------------------------ */
function QuestionBlock({ q, index, onAnswer, selected }) {
  const { cfg, colors, sans } = useTheme();
  const answered = selected !== undefined;
  return (
    <div className="mb-6 pb-6 border-b" style={{ borderColor: colors.line }}>
      <p style={{ ...sans, color: colors.ink }} className="font-medium mb-3">
        {index + 1}. {q.question}
      </p>
      <div className="grid sm:grid-cols-2 gap-2">
        {q.options.map((opt, i) => {
          const isCorrect = i === q.correctIndex;
          const isSelected = selected === i;
          let style = { borderColor: colors.line, color: colors.ink, backgroundColor: colors.card };
          if (answered && isSelected && isCorrect) style = { borderColor: colors.success, color: colors.success, backgroundColor: mix(colors.success, "#ffffff", 0.9) };
          else if (answered && isSelected && !isCorrect) style = { borderColor: colors.error, color: colors.error, backgroundColor: mix(colors.error, "#ffffff", 0.9) };
          else if (answered && isCorrect) style = { borderColor: colors.success, color: colors.success, backgroundColor: colors.card };
          return (
            <button key={i} disabled={answered} onClick={() => onAnswer(i)} className="flex items-center justify-between px-3 py-2 border text-sm text-left rounded-sm" style={{ ...sans, ...style }}>
              <span>{opt}</span>
              {answered && isSelected && (isCorrect ? <Check size={14} /> : <X size={14} />)}
            </button>
          );
        })}
      </div>
      {answered && q.explanation && (
        <p style={{ ...sans, color: "#5B6472" }} className="text-xs mt-2 italic">
          {q.explanation}
        </p>
      )}
    </div>
  );
}

function ExerciseDetail({ exercise, setView, track, currentUser, priorSubmission, onRecordSubmission }) {
  const { cfg, colors, serif, sans, trackInfo } = useTheme();
  const t = trackInfo(track);
  const [answers, setAnswers] = useState({});
  const [transcriptShown, setTranscriptShown] = useState(false);
  const [playing, setPlaying] = useState(false);
  const [draft, setDraft] = useState("");
  const [draftStatus, setDraftStatus] = useState("idle");
  const submittedRef = useRef(false);

  useEffect(() => {
    setAnswers({});
    setTranscriptShown(false);
    setDraft("");
    setDraftStatus("idle");
    submittedRef.current = false;
    if (exercise.type === "writing" && currentUser) {
      (async () => {
        const val = await api.fetchWritingDraft(currentUser.id, exercise.id);
        if (val) setDraft(val);
      })();
    }
  }, [exercise.id, currentUser]);

  const handleAnswer = useCallback((qId, i) => setAnswers((prev) => ({ ...prev, [qId]: i })), []);
  const total = exercise.questions?.length || 0;
  const answeredCount = Object.keys(answers).length;
  const score = exercise.questions?.reduce((acc, q) => (answers[q.id] === q.correctIndex ? acc + 1 : acc), 0) || 0;

  useEffect(() => {
    if (total > 0 && answeredCount === total && !submittedRef.current && currentUser && onRecordSubmission) {
      submittedRef.current = true;
      onRecordSubmission({
        id: uid(),
        userId: currentUser.id,
        userName: currentUser.name,
        userEmail: currentUser.email,
        exerciseId: exercise.id,
        exerciseTitle: exercise.title,
        exerciseType: exercise.type,
        track: exercise.track,
        level: exercise.level,
        score,
        total,
        completedAt: new Date().toISOString(),
      });
    }
  }, [answeredCount, total, score, currentUser, exercise, onRecordSubmission]);

  function playAudio() {
    if (!("speechSynthesis" in window)) return;
    window.speechSynthesis.cancel();
    const utter = new SpeechSynthesisUtterance(exercise.passage);
    utter.lang = "en-US";
    utter.rate = 0.95;
    utter.onstart = () => setPlaying(true);
    utter.onend = () => setPlaying(false);
    utter.onerror = () => setPlaying(false);
    window.speechSynthesis.speak(utter);
  }

  async function saveDraft() {
    if (!currentUser) return;
    setDraftStatus("saving");
    try {
      await api.saveWritingDraft(currentUser.id, exercise.id, draft);
      setDraftStatus("saved");
    } catch {
      setDraftStatus("idle");
    }
  }

  const wordCount = draft.trim().length ? draft.trim().split(/\s+/).length : 0;

  return (
    <div className="max-w-3xl mx-auto px-6 py-12">
      <button onClick={() => setView({ name: exercise.type })} className="flex items-center gap-1 text-sm mb-6" style={{ ...sans, color: "#5B6472" }}>
        <ChevronLeft size={16} /> Volver a {cfg.categoryLabels[exercise.type]}
      </button>

      <div className="flex items-center gap-3 mb-1">
        <CategoryIcon catKey={exercise.type} size={20} style={{ color: t.accent }} />
        <h2 style={{ ...serif, color: colors.ink }} className="text-2xl font-semibold">
          {exercise.title}
        </h2>
      </div>
      <div style={{ ...sans, color: "#5B6472" }} className="text-xs flex items-center gap-3 mb-6">
        <LevelBadge level={exercise.level} accent={t.accent} />
        <span>Publicado el {formatDate(exercise.dateAdded)}</span>
      </div>
      <GoldRule accent={t.accent} className="mb-8" />

      {priorSubmission && (
        <div
          className="mb-6 p-3 border flex items-center justify-between text-sm"
          style={{ borderColor: t.accent, backgroundColor: t.accentSoft, ...sans }}
        >
          <span style={{ color: t.accentDeep }}>
            Ya completaste este examen: {priorSubmission.score}/{priorSubmission.total} el {formatDate(priorSubmission.completedAt)}.
          </span>
          <span style={{ color: t.accentDeep }} className="font-semibold">Puedes repetirlo</span>
        </div>
      )}

      {exercise.instructions && (
        <p style={{ ...sans, color: "#5B6472" }} className="mb-6 italic">
          {exercise.instructions}
        </p>
      )}

      {exercise.type === "grammar" && exercise.theoryFileUrl && (
        <a
          href={exercise.theoryFileUrl}
          download={exercise.theoryFileName || "teoria"}
          className="flex items-center gap-2 p-4 mb-6 border text-sm font-medium"
          style={{ borderColor: t.accent, backgroundColor: t.accentSoft, color: t.accentDeep, ...sans }}
        >
          <FileText size={16} />
          Descargar teoría de este ejercicio {exercise.theoryFileName ? `(${exercise.theoryFileName})` : ""}
        </a>
      )}

      {exercise.type === "reading" && (
        <div className="p-5 mb-8 border text-sm leading-relaxed" style={{ borderColor: colors.line, backgroundColor: colors.card, color: colors.ink, ...sans }}>
          {exercise.passage}
        </div>
      )}

      {exercise.type === "listening" && (
        <div className="p-5 mb-8 border flex flex-col items-start gap-3" style={{ borderColor: colors.line, backgroundColor: colors.card }}>
          {exercise.audioUrl ? (
            <audio controls src={exercise.audioUrl} className="w-full" />
          ) : (
            <>
              <button onClick={playAudio} className="flex items-center gap-2 px-4 py-2 text-sm font-semibold rounded-sm" style={{ ...sans, backgroundColor: colors.ink, color: colors.bg }}>
                {playing ? <Volume2 size={16} /> : <Play size={16} />}
                {playing ? "Reproduciendo…" : "Reproducir audio"}
              </button>
              <p style={{ ...sans, color: "#5B6472" }} className="text-xs">
                Se reproduce con voz sintética en inglés. Si tu dispositivo no soporta audio, puedes leer la transcripción.
              </p>
            </>
          )}
          <button onClick={() => setTranscriptShown((s) => !s)} className="text-xs underline" style={{ ...sans, color: "#5B6472" }}>
            {transcriptShown ? "Ocultar transcripción" : "Ver transcripción"}
          </button>
          {transcriptShown && (
            <p style={{ ...sans, color: colors.ink, borderColor: colors.line }} className="text-sm leading-relaxed border-t pt-3 mt-1">
              {exercise.passage}
            </p>
          )}
        </div>
      )}

      {exercise.type === "writing" ? (
        <div>
          <div className="p-5 mb-5 border text-sm leading-relaxed" style={{ borderColor: colors.line, backgroundColor: colors.card, color: colors.ink, ...sans }}>
            {exercise.passage}
          </div>
          <textarea
            value={draft}
            onChange={(e) => { setDraft(e.target.value); setDraftStatus("idle"); }}
            rows={10}
            placeholder="Escribe tu redacción aquí…"
            className="w-full p-4 border text-sm leading-relaxed resize-y"
            style={{ ...sans, borderColor: colors.line, color: colors.ink }}
          />
          <div className="flex items-center justify-between mt-3">
            <span style={{ ...sans, color: wordCount >= (exercise.minWords || 0) ? colors.success : "#5B6472" }} className="text-xs">
              {wordCount} palabras {exercise.minWords ? `(mínimo ${exercise.minWords})` : ""}
            </span>
            <button onClick={saveDraft} disabled={!draft.trim()} className="px-4 py-2 text-sm font-semibold rounded-sm disabled:opacity-40" style={{ ...sans, backgroundColor: colors.ink, color: colors.bg }}>
              {draftStatus === "saving" ? "Guardando…" : draftStatus === "saved" ? "Guardado ✓" : "Guardar borrador"}
            </button>
          </div>
        </div>
      ) : (
        <div>
          {exercise.questions.map((q, i) => (
            <QuestionBlock key={q.id} q={q} index={i} selected={answers[q.id]} onAnswer={(idx) => handleAnswer(q.id, idx)} />
          ))}
          {total > 0 && (
            <div className="mt-4 p-4 border flex items-center justify-between" style={{ borderColor: colors.line, backgroundColor: colors.card }}>
              <span style={{ ...sans, color: colors.ink }} className="text-sm font-medium">
                {answeredCount === total ? "Resultado final" : "Progreso"}
              </span>
              <span style={{ ...serif, color: colors.ink }} className="text-lg font-semibold">
                {score} / {total}
              </span>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

