function authErrorMessage(err) {
  const msg = err?.message || "";
  if (/invalid login credentials/i.test(msg)) return "Email o contraseña incorrectos.";
  if (/already registered|already exists/i.test(msg)) return "Ya existe una cuenta con ese email. Prueba a iniciar sesión.";
  if (/password/i.test(msg) && /least|short/i.test(msg)) return "La contraseña es demasiado corta.";
  return msg || "Algo ha fallado. Inténtalo de nuevo.";
}

function StudentAuthGate({ profile, onLogout, children }) {
  const [mode, setMode] = useState("signup");
  const [form, setForm] = useState({ name: "", email: "", password: "", confirm: "" });
  const [error, setError] = useState("");
  const [info, setInfo] = useState("");
  const [busy, setBusy] = useState(false);

  async function handleSignup(e) {
    e.preventDefault();
    setError("");
    setInfo("");
    if (!form.name.trim() || !form.email.trim() || form.password.length < 6) {
      setError("Rellena tu nombre, un email válido y una contraseña de al menos 6 caracteres.");
      return;
    }
    if (form.password !== form.confirm) {
      setError("Las contraseñas no coinciden.");
      return;
    }
    setBusy(true);
    try {
      const result = await api.signUp({ name: form.name.trim(), email: form.email.trim().toLowerCase(), password: form.password });
      if (!result.session) {
        setInfo("Cuenta creada. Revisa tu email para confirmar la cuenta y luego inicia sesión.");
        setMode("login");
      }
    } catch (err) {
      setError(authErrorMessage(err));
    }
    setBusy(false);
  }

  async function handleLogin(e) {
    e.preventDefault();
    setError("");
    setInfo("");
    setBusy(true);
    try {
      await api.signIn({ email: form.email.trim().toLowerCase(), password: form.password });
    } catch (err) {
      setError(authErrorMessage(err));
    }
    setBusy(false);
  }

  async function handleResetRequest(e) {
    e.preventDefault();
    setError("");
    setInfo("");
    if (!form.email.trim()) {
      setError("Escribe tu email.");
      return;
    }
    setBusy(true);
    try {
      await api.requestPasswordReset(form.email.trim().toLowerCase());
      setInfo("Si existe una cuenta con ese email, te hemos enviado un enlace para cambiar la contraseña.");
    } catch (err) {
      setError(authErrorMessage(err));
    }
    setBusy(false);
  }

  if (profile) {
    if (profile.status === "approved") return children;
    if (profile.status === "rejected") return <RejectedScreen user={profile} onLogout={onLogout} />;
    return <PendingScreen user={profile} onLogout={onLogout} />;
  }

  return (
    <AuthScreen
      mode={mode}
      setMode={setMode}
      form={form}
      setForm={setForm}
      error={error}
      info={info}
      busy={busy}
      onSignup={handleSignup}
      onLogin={handleLogin}
      onResetRequest={handleResetRequest}
    />
  );
}

