/* ------------------------------------------------------------------ */
/*  Admin — tab: Emojis (biblioteca de iconos propios)                  */
/* ------------------------------------------------------------------ */
function EmojiPreview({ value, size = 28 }) {
  if (!value) return null;
  if (isImageValue(value)) {
    return <img src={value} alt="" style={{ height: size, width: size, objectFit: "contain" }} />;
  }
  return <span style={{ fontSize: size, lineHeight: 1 }}>{value}</span>;
}

function EmojisTab({ cfg, updateConfig }) {
  const { sans, serif } = useTheme();
  const [label, setLabel] = useState("");
  const [value, setValue] = useState("");
  const [copiedId, setCopiedId] = useState(null);
  const [uploadBusy, setUploadBusy] = useState(false);

  function addItem(e) {
    e.preventDefault();
    if (!value.trim()) return;
    const item = { id: uid(), label: label.trim() || "Sin nombre", value: value.trim() };
    updateConfig({ emojiLibrary: [item, ...cfg.emojiLibrary] });
    setLabel("");
    setValue("");
  }

  async function handleUploadIcon(e) {
    const file = e.target.files?.[0];
    if (!file) return;
    setUploadBusy(true);
    try {
      const url = await api.uploadFile(file, "icons");
      setValue(url);
      if (!label.trim()) setLabel(file.name.replace(/\.[^.]+$/, ""));
    } catch {
      /* leave the form as-is so the admin can retry */
    }
    setUploadBusy(false);
    e.target.value = "";
  }

  function removeItem(id) {
    updateConfig({ emojiLibrary: cfg.emojiLibrary.filter((it) => it.id !== id) });
  }

  async function copyValue(item) {
    try {
      await navigator.clipboard.writeText(item.value);
      setCopiedId(item.id);
      setTimeout(() => setCopiedId(null), 1500);
    } catch {
      /* clipboard may be unavailable — the value is still visible to copy by hand */
    }
  }

  return (
    <div className="max-w-2xl space-y-6">
      <div>
        <h4 style={{ ...serif, color: cfg.colors.ink }} className="text-base font-semibold mb-1">
          Tu biblioteca de emojis e iconos
        </h4>
        <p style={{ ...sans, color: "#5B6472" }} className="text-sm mb-4">
          Guarda aquí los emojis o los iconos que diseñes (pega un emoji nativo, o la URL / base64 de una imagen pequeña que hayas
          creado) para tenerlos a mano. Luego copia el valor y pégalo en cualquier campo de icono de la web: categorías, áreas, etc.
        </p>
        <form onSubmit={addItem} className="flex flex-wrap items-end gap-3 p-4 border" style={{ borderColor: cfg.colors.line }}>
          <label className="text-sm" style={sans}>
            Nombre
            <input value={label} onChange={(e) => setLabel(e.target.value)} placeholder="Ej. Estrella dorada" className="mt-1 border px-3 py-2 text-sm w-40" style={{ borderColor: cfg.colors.line }} />
          </label>
          <label className="text-sm flex-1 min-w-[220px]" style={sans}>
            Emoji, o URL/base64 de una imagen
            <input value={value} onChange={(e) => setValue(e.target.value)} placeholder="⭐ o sube una imagen →" className="mt-1 w-full border px-3 py-2 text-sm font-mono" style={{ borderColor: cfg.colors.line }} />
          </label>
          <label
            className="inline-flex items-center gap-2 px-3 py-2 text-xs font-semibold rounded-sm cursor-pointer w-fit mb-[1px]"
            style={{ ...sans, backgroundColor: cfg.colors.ink, color: cfg.colors.bg, opacity: uploadBusy ? 0.5 : 1 }}
          >
            {uploadBusy ? "Subiendo…" : "Subir imagen"}
            <input type="file" accept="image/*" onChange={handleUploadIcon} disabled={uploadBusy} className="hidden" />
          </label>
          <div className="flex items-center gap-2 pb-1">
            <EmojiPreview value={value} size={26} />
            <button type="submit" className="px-4 py-2 text-sm font-semibold rounded-sm" style={{ ...sans, backgroundColor: cfg.colors.ink, color: cfg.colors.bg }}>
              Guardar
            </button>
          </div>
        </form>
      </div>

      <div>
        {cfg.emojiLibrary.length === 0 ? (
          <p style={{ ...sans, color: "#5B6472" }} className="text-sm italic">Todavía no has guardado ningún emoji o icono.</p>
        ) : (
          <div className="grid sm:grid-cols-2 gap-3">
            {cfg.emojiLibrary.map((item) => (
              <div key={item.id} className="flex items-center gap-3 p-3 border" style={{ borderColor: cfg.colors.line }}>
                <div className="w-10 h-10 flex items-center justify-center border shrink-0" style={{ borderColor: cfg.colors.line }}>
                  <EmojiPreview value={item.value} />
                </div>
                <div className="flex-1 min-w-0">
                  <div style={{ ...sans, color: cfg.colors.ink }} className="text-sm font-medium truncate">{item.label}</div>
                  <div style={{ ...sans, color: "#5B6472" }} className="text-[11px] truncate font-mono">{item.value}</div>
                </div>
                <button type="button" onClick={() => copyValue(item)} className="text-xs font-semibold shrink-0" style={{ ...sans, color: cfg.colors.civilAccent }}>
                  {copiedId === item.id ? "¡Copiado!" : "Copiar"}
                </button>
                <button type="button" onClick={() => removeItem(item.id)} style={{ color: cfg.colors.error }} className="shrink-0">
                  <Trash2 size={15} />
                </button>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

