/* ------------------------------------------------------------------ */
/*  Admin — tab: Acceso (password)                                      */
/* ------------------------------------------------------------------ */
function AccessTab({ profile }) {
  const { cfg, sans, serif } = useTheme();
  const [next, setNext] = useState("");
  const [confirm, setConfirm] = useState("");
  const [message, setMessage] = useState("");
  const [busy, setBusy] = useState(false);

  async function handleSet(e) {
    e.preventDefault();
    setMessage("");
    if (next.length < 6) { setMessage("Usa una contraseña de al menos 6 caracteres."); return; }
    if (next !== confirm) { setMessage("Las dos contraseñas no coinciden."); return; }
    setBusy(true);
    const { error } = await supabase.auth.updateUser({ password: next });
    setBusy(false);
    if (!error) {
      setMessage("Contraseña actualizada.");
      setNext(""); setConfirm("");
    } else {
      setMessage("No se pudo guardar. Inténtalo de nuevo.");
    }
  }

  return (
    <div className="max-w-md space-y-4">
      <h4 style={{ ...serif, color: cfg.colors.ink }} className="text-base font-semibold">
        Cambiar mi contraseña
      </h4>
      <p style={{ ...sans, color: "#5B6472" }} className="text-sm">
        Sesión iniciada como <strong>{profile?.email}</strong>. El acceso de administrador se gestiona con Supabase Auth: para dar
        permisos de administrador a otra cuenta, actualiza <code>is_admin</code> en la tabla <code>profiles</code> desde el panel de
        Supabase.
      </p>
      <form onSubmit={handleSet} className="space-y-3">
        <input type="password" value={next} onChange={(e) => setNext(e.target.value)} placeholder="Nueva contraseña" className="w-full border px-3 py-2 text-sm" style={{ borderColor: cfg.colors.line }} />
        <input type="password" value={confirm} onChange={(e) => setConfirm(e.target.value)} placeholder="Confirmar contraseña" className="w-full border px-3 py-2 text-sm" style={{ borderColor: cfg.colors.line }} />
        {message && <p style={{ ...sans, color: cfg.colors.ink }} className="text-xs">{message}</p>}
        <button type="submit" disabled={busy} className="px-4 py-2 text-sm font-semibold rounded-sm" style={{ ...sans, backgroundColor: cfg.colors.ink, color: cfg.colors.bg }}>
          {busy ? "Guardando…" : "Actualizar contraseña"}
        </button>
      </form>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Admin — tab: Alumnos (aprobar / rechazar cuentas)                    */
/* ------------------------------------------------------------------ */
const PLAN_LABELS = { individual: "Clases individuales", "3months": "Pack 3 meses", "6months": "Pack 6 meses" };

function computePlanEndDate(plan, startDate) {
  if (!startDate || plan === "individual") return null;
  const d = new Date(startDate + "T00:00:00");
  d.setMonth(d.getMonth() + (plan === "3months" ? 3 : 6));
  return d;
}

function PlanBadge({ plan, planStartDate, colors, sans }) {
  if (plan === "individual") return null;
  if (!planStartDate) {
    return <span style={{ ...sans, color: "#5B6472" }} className="text-[10px] italic">Sin fecha de inicio</span>;
  }
  const end = computePlanEndDate(plan, planStartDate);
  const daysLeft = Math.ceil((end.getTime() - Date.now()) / (1000 * 60 * 60 * 24));
  let color = colors.success;
  let label = `Activo hasta ${formatDate(end.toISOString())}`;
  if (daysLeft < 0) {
    color = colors.error;
    label = `Caducado (${formatDate(end.toISOString())})`;
  } else if (daysLeft <= 14) {
    color = "#B8860B";
    label = `Caduca pronto (${formatDate(end.toISOString())})`;
  }
  return (
    <span style={{ ...sans, backgroundColor: mix(color, "#ffffff", 0.85), color }} className="text-[10px] font-semibold px-1.5 py-0.5 rounded-sm w-fit">
      {label}
    </span>
  );
}

function StudentsTab({ users, setUsers, currentAdminId }) {
  const { cfg, sans, serif } = useTheme();
  const [filter, setFilter] = useState("pending");
  const visibleUsers = users.filter((u) => u.id !== currentAdminId);

  async function setStatus(id, status) {
    try {
      await api.updateProfileStatus(id, status);
      setUsers((prev) => prev.map((u) => (u.id === id ? { ...u, status } : u)));
    } catch {
      /* the list simply won't reflect the change; the button remains clickable to retry */
    }
  }
  async function updatePlan(id, patch) {
    const u = users.find((x) => x.id === id);
    if (!u) return;
    const nextPlan = patch.plan ?? u.plan;
    const nextStart = patch.planStartDate !== undefined ? patch.planStartDate : u.planStartDate;
    try {
      await api.updateProfilePlan(id, nextPlan, nextStart);
      setUsers((prev) => prev.map((x) => (x.id === id ? { ...x, plan: nextPlan, planStartDate: nextStart } : x)));
    } catch {
      /* the list simply won't reflect the change; the controls remain editable to retry */
    }
  }
  async function handleDelete(id) {
    try {
      await api.deleteProfile(id);
      setUsers((prev) => prev.filter((u) => u.id !== id));
    } catch {
      /* leave the row in place so the admin can retry */
    }
  }

  const pendingCount = visibleUsers.filter((u) => u.status === "pending").length;
  const filters = [
    { key: "pending", label: `Pendientes (${pendingCount})` },
    { key: "approved", label: "Aprobados" },
    { key: "rejected", label: "Rechazados" },
    { key: "all", label: "Todos" },
  ];
  const filtered = [...visibleUsers]
    .filter((u) => filter === "all" || u.status === filter)
    .sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));

  return (
    <div className="max-w-3xl space-y-6">
      <div>
        <h4 style={{ ...serif, color: cfg.colors.ink }} className="text-base font-semibold mb-1">
          Cuentas de alumnos
        </h4>
        <p style={{ ...sans, color: "#5B6472" }} className="text-sm">
          Da acceso a los alumnos que se han registrado. Mientras no los apruebes, solo ven la pantalla de "pendiente de aprobación".
        </p>
      </div>

      <div className="flex flex-wrap gap-1 border-b" style={{ borderColor: cfg.colors.line }}>
        {filters.map((f) => (
          <button
            key={f.key}
            onClick={() => setFilter(f.key)}
            className="px-3 py-2 text-sm font-medium border-b-2 -mb-px"
            style={{ ...sans, borderColor: filter === f.key ? cfg.colors.ink : "transparent", color: filter === f.key ? cfg.colors.ink : "#5B6472" }}
          >
            {f.label}
          </button>
        ))}
      </div>

      {filtered.length === 0 ? (
        <p style={{ ...sans, color: "#5B6472" }} className="text-sm italic">No hay alumnos en esta categoría.</p>
      ) : (
        <ul className="space-y-2">
          {filtered.map((u) => (
            <li key={u.id} className="flex flex-col gap-3 p-3 border" style={{ borderColor: cfg.colors.line, backgroundColor: cfg.colors.card }}>
              <div className="flex items-center justify-between gap-3 flex-wrap">
                <div className="min-w-0">
                  <div style={{ ...sans, color: cfg.colors.ink }} className="text-sm font-medium truncate">{u.name || "(sin nombre)"}</div>
                  <div style={{ ...sans, color: "#5B6472" }} className="text-xs truncate flex items-center gap-1">
                    {u.email} <span className="mx-1">·</span> <CalendarDays size={11} /> Se apuntó el {formatDate(u.createdAt)}
                  </div>
                </div>
                <div className="flex items-center gap-2 shrink-0">
                  {u.status !== "approved" && (
                    <button onClick={() => setStatus(u.id, "approved")} className="px-2.5 py-1 text-xs font-semibold rounded-sm" style={{ ...sans, backgroundColor: cfg.colors.success, color: "#fff" }}>
                      Aprobar
                    </button>
                  )}
                  {u.status !== "rejected" && (
                    <button onClick={() => setStatus(u.id, "rejected")} className="px-2.5 py-1 text-xs font-semibold rounded-sm border" style={{ ...sans, borderColor: cfg.colors.error, color: cfg.colors.error }}>
                      Rechazar
                    </button>
                  )}
                  {u.status !== "pending" && (
                    <button onClick={() => setStatus(u.id, "pending")} className="px-2.5 py-1 text-xs font-semibold rounded-sm border" style={{ ...sans, borderColor: cfg.colors.line, color: "#5B6472" }}>
                      Revocar
                    </button>
                  )}
                  <button onClick={() => handleDelete(u.id)} style={{ color: cfg.colors.error }} title="Eliminar cuenta">
                    <Trash2 size={15} />
                  </button>
                </div>
              </div>

              <div className="flex items-center gap-3 flex-wrap pt-2 border-t" style={{ borderColor: cfg.colors.line }}>
                <label className="text-xs flex items-center gap-1.5" style={sans}>
                  Pack:
                  <select
                    value={u.plan || "individual"}
                    onChange={(e) => updatePlan(u.id, { plan: e.target.value })}
                    className="border px-2 py-1 text-xs"
                    style={{ borderColor: cfg.colors.line }}
                  >
                    {Object.entries(PLAN_LABELS).map(([key, label]) => (
                      <option key={key} value={key}>{label}</option>
                    ))}
                  </select>
                </label>
                {u.plan !== "individual" && (
                  <label className="text-xs flex items-center gap-1.5" style={sans}>
                    Inicio:
                    <input
                      type="date"
                      value={u.planStartDate || ""}
                      onChange={(e) => updatePlan(u.id, { planStartDate: e.target.value })}
                      className="border px-2 py-1 text-xs"
                      style={{ borderColor: cfg.colors.line }}
                    />
                  </label>
                )}
                <PlanBadge plan={u.plan || "individual"} planStartDate={u.planStartDate} colors={cfg.colors} sans={sans} />
              </div>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Admin — tab: Progreso (resultados de los exámenes tipo por alumno)  */
/* ------------------------------------------------------------------ */
function ProgressTab({ users, submissions }) {
  const { cfg, sans, serif } = useTheme();
  const [selectedStudent, setSelectedStudent] = useState("all");
  const [typeFilter, setTypeFilter] = useState("all");

  const byStudent = useMemo(() => {
    const map = {};
    submissions.forEach((s) => {
      if (!map[s.userId]) map[s.userId] = [];
      map[s.userId].push(s);
    });
    return map;
  }, [submissions]);

  const studentSummaries = useMemo(() => {
    return Object.entries(byStudent).map(([userId, list]) => {
      const user = users.find((u) => u.id === userId);
      const totalPct = list.reduce((acc, s) => acc + (s.total ? s.score / s.total : 0), 0);
      const avgPct = list.length ? Math.round((totalPct / list.length) * 100) : 0;
      return {
        userId,
        name: user ? user.name : "(cuenta eliminada)",
        email: user ? user.email : "—",
        count: list.length,
        avgPct,
      };
    }).sort((a, b) => b.count - a.count);
  }, [byStudent, users]);

  const filtered = useMemo(() => {
    return [...submissions]
      .filter((s) => selectedStudent === "all" || s.userId === selectedStudent)
      .filter((s) => typeFilter === "all" || s.exerciseType === typeFilter)
      .sort((a, b) => new Date(b.completedAt) - new Date(a.completedAt));
  }, [submissions, selectedStudent, typeFilter]);

  if (submissions.length === 0) {
    return (
      <div className="max-w-2xl">
        <p style={{ ...sans, color: "#5B6472" }} className="text-sm">
          Todavía no hay ningún examen completado. En cuanto tus alumnos aprobados terminen un examen de gramática, listening o
          reading, su resultado aparecerá aquí automáticamente.
        </p>
      </div>
    );
  }

  return (
    <div className="max-w-4xl space-y-8">
      <div>
        <h4 style={{ ...serif, color: cfg.colors.ink }} className="text-base font-semibold mb-3">
          Resumen por alumno
        </h4>
        <div className="grid sm:grid-cols-2 gap-3">
          {studentSummaries.map((s) => (
            <button
              key={s.userId}
              onClick={() => setSelectedStudent(s.userId === selectedStudent ? "all" : s.userId)}
              className="text-left p-3 border"
              style={{ borderColor: selectedStudent === s.userId ? cfg.colors.ink : cfg.colors.line, backgroundColor: cfg.colors.card }}
            >
              <div style={{ ...sans, color: cfg.colors.ink }} className="text-sm font-medium">{s.name}</div>
              <div style={{ ...sans, color: "#5B6472" }} className="text-xs mb-1">{s.email}</div>
              <div style={{ ...sans, color: cfg.colors.success }} className="text-xs font-semibold">
                {s.count} examen{s.count === 1 ? "" : "es"} · media {s.avgPct}%
              </div>
            </button>
          ))}
        </div>
      </div>

      <div>
        <div className="flex items-center justify-between mb-3 flex-wrap gap-2">
          <h4 style={{ ...serif, color: cfg.colors.ink }} className="text-base font-semibold">
            Todos los intentos
          </h4>
          <div className="flex items-center gap-2">
            <select value={typeFilter} onChange={(e) => setTypeFilter(e.target.value)} className="border px-2 py-1.5 text-xs" style={{ ...sans, borderColor: cfg.colors.line }}>
              <option value="all">Todos los tipos</option>
              {CATEGORY_KEYS.map((k) => <option key={k} value={k}>{cfg.categoryLabels[k]}</option>)}
            </select>
            {selectedStudent !== "all" && (
              <button onClick={() => setSelectedStudent("all")} className="text-xs underline" style={{ ...sans, color: "#5B6472" }}>
                Quitar filtro de alumno
              </button>
            )}
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm border-collapse">
            <thead>
              <tr style={{ ...sans, color: "#5B6472" }} className="text-left text-xs uppercase">
                <th className="pb-2 pr-3">Alumno</th>
                <th className="pb-2 pr-3">Examen</th>
                <th className="pb-2 pr-3">Tipo</th>
                <th className="pb-2 pr-3">Resultado</th>
                <th className="pb-2">Fecha</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map((s) => (
                <tr key={s.id} className="border-t" style={{ borderColor: cfg.colors.line }}>
                  <td style={{ ...sans, color: cfg.colors.ink }} className="py-2 pr-3">{s.userName || s.userEmail}</td>
                  <td style={{ ...sans, color: cfg.colors.ink }} className="py-2 pr-3">{s.exerciseTitle}</td>
                  <td style={{ ...sans, color: "#5B6472" }} className="py-2 pr-3">{cfg.categoryLabels[s.exerciseType] || s.exerciseType}</td>
                  <td style={{ ...sans, color: cfg.colors.ink }} className="py-2 pr-3 font-semibold">
                    {s.score}/{s.total} ({s.total ? Math.round((s.score / s.total) * 100) : 0}%)
                  </td>
                  <td style={{ ...sans, color: "#5B6472" }} className="py-2">{formatDate(s.completedAt)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Admin — tab: Artículos (CRUD con imagen de portada)                 */
/* ------------------------------------------------------------------ */
function emptyArticleForm(track = "civil") {
  return { track, title: "", coverImageUrl: "", excerpt: "", body: "", icon: "" };
}

function ArticlesTab({ articles, setArticles, track }) {
  const { cfg, sans, trackInfo } = useTheme();
  const [form, setForm] = useState(emptyArticleForm(track));
  const [message, setMessage] = useState("");
  const [filterTrack, setFilterTrack] = useState(track);
  const [coverBusy, setCoverBusy] = useState(false);
  const [editingId, setEditingId] = useState(null);

  function startEdit(a) {
    setEditingId(a.id);
    setForm({ track: a.track, title: a.title, coverImageUrl: a.coverImageUrl, excerpt: a.excerpt, body: a.body, icon: a.icon || "" });
    setMessage("");
  }

  function cancelEdit() {
    setEditingId(null);
    setForm(emptyArticleForm(track));
    setMessage("");
  }

  function updateField(field, value) {
    setForm((f) => ({ ...f, [field]: value }));
  }

  async function handleUploadCover(e) {
    const file = e.target.files?.[0];
    if (!file) return;
    setCoverBusy(true);
    try {
      const url = await api.uploadFile(file, "articles");
      updateField("coverImageUrl", url);
    } catch {
      setMessage("No se pudo subir la imagen. Inténtalo de nuevo.");
    }
    setCoverBusy(false);
    e.target.value = "";
  }

  async function handleSubmit(e) {
    e.preventDefault();
    if (!form.title.trim() || !form.body.trim()) {
      setMessage("Añade al menos un título y el texto del artículo.");
      return;
    }
    const articleData = {
      track: form.track,
      title: form.title.trim(),
      coverImageUrl: form.coverImageUrl.trim(),
      excerpt: form.excerpt.trim() || form.body.trim().slice(0, 140),
      body: form.body.trim(),
      icon: form.icon.trim(),
    };
    try {
      if (editingId) {
        const updated = await api.updateArticle(editingId, articleData);
        setArticles((prev) => prev.map((a) => (a.id === editingId ? updated : a)));
        setMessage("Cambios guardados.");
      } else {
        const created = await api.insertArticle(articleData);
        setArticles((prev) => [created, ...prev]);
        setMessage("Artículo publicado.");
      }
    } catch {
      setMessage("No se pudo guardar. Inténtalo de nuevo.");
    }
    setEditingId(null);
    setForm(emptyArticleForm(form.track));
  }

  async function handleDelete(id) {
    try {
      await api.deleteArticle(id);
      setArticles((prev) => prev.filter((a) => a.id !== id));
      if (editingId === id) cancelEdit();
    } catch {
      setMessage("No se pudo eliminar. Inténtalo de nuevo.");
    }
  }

  const filteredList = articles.filter((a) => a.track === filterTrack);

  return (
    <div className="grid lg:grid-cols-[1.1fr_0.9fr] gap-10">
      <div>
        <p style={{ ...sans, color: "#5B6472" }} className="text-sm mb-2">
          Publica artículos de blog para el área civil o militar, con una imagen de portada opcional.
        </p>
        <form onSubmit={handleSubmit} className="space-y-4">
          <label className="text-sm" style={sans}>
            Área
            <select value={form.track} onChange={(e) => updateField("track", e.target.value)} className="mt-1 w-full border px-3 py-2" style={{ borderColor: cfg.colors.line }}>
              <option value="civil">{cfg.copy.civil.label}</option>
              <option value="military">{cfg.copy.military.label}</option>
            </select>
          </label>
          <label className="text-sm block" style={sans}>
            Título
            <input value={form.title} onChange={(e) => updateField("title", e.target.value)} className="mt-1 w-full border px-3 py-2" style={{ borderColor: cfg.colors.line }} />
          </label>
          <div className="text-sm" style={sans}>
            Icono del artículo (opcional — insignia junto al título)
            <div className="flex items-center gap-3 mt-1">
              <div className="w-10 h-10 border flex items-center justify-center shrink-0" style={{ borderColor: cfg.colors.line }}>
                <EmojiPreview value={form.icon} size={20} />
              </div>
              <input
                value={form.icon}
                onChange={(e) => updateField("icon", e.target.value)}
                placeholder="🔤 o elige de tu biblioteca abajo"
                className="flex-1 border px-3 py-2 text-xs font-mono"
                style={{ borderColor: cfg.colors.line }}
              />
            </div>
            <LibraryPicker library={cfg.emojiLibrary} onPick={(v) => updateField("icon", v)} />
          </div>
          <div className="text-sm" style={sans}>
            Imagen de portada (opcional)
            <div className="mt-1 flex items-center gap-3 flex-wrap">
              <label
                className="inline-flex items-center gap-2 px-3 py-1.5 text-xs font-semibold rounded-sm cursor-pointer w-fit"
                style={{ ...sans, backgroundColor: cfg.colors.ink, color: cfg.colors.bg, opacity: coverBusy ? 0.5 : 1 }}
              >
                <ImageIcon size={13} />
                {coverBusy ? "Subiendo…" : "Subir imagen"}
                <input type="file" accept="image/*" onChange={handleUploadCover} disabled={coverBusy} className="hidden" />
              </label>
              {form.coverImageUrl && (
                <button type="button" onClick={() => updateField("coverImageUrl", "")} className="text-xs underline" style={{ ...sans, color: "#5B6472" }}>
                  Quitar imagen
                </button>
              )}
            </div>
          </div>
          {form.coverImageUrl && <img src={form.coverImageUrl} alt="" className="w-full h-32 object-cover border" style={{ borderColor: cfg.colors.line }} />}
          <label className="text-sm block" style={sans}>
            Resumen breve (opcional, se usa en la tarjeta)
            <input value={form.excerpt} onChange={(e) => updateField("excerpt", e.target.value)} className="mt-1 w-full border px-3 py-2" style={{ borderColor: cfg.colors.line }} />
          </label>
          <label className="text-sm block" style={sans}>
            Texto del artículo (un párrafo por línea)
            <textarea value={form.body} onChange={(e) => updateField("body", e.target.value)} rows={8} className="mt-1 w-full border px-3 py-2" style={{ borderColor: cfg.colors.line }} />
          </label>
          <div className="flex items-center gap-3">
            <button type="submit" className="px-5 py-2.5 text-sm font-semibold rounded-sm" style={{ ...sans, backgroundColor: cfg.colors.ink, color: cfg.colors.bg }}>
              {editingId ? "Guardar cambios" : "Publicar artículo"}
            </button>
            {editingId && (
              <button type="button" onClick={cancelEdit} className="text-xs underline" style={{ ...sans, color: "#5B6472" }}>
                Cancelar edición
              </button>
            )}
            {message && <span style={{ ...sans, color: "#5B6472" }} className="text-xs">{message}</span>}
          </div>
        </form>
      </div>

      <div>
        <div className="flex items-center justify-between mb-3">
          <span style={{ ...sans, color: cfg.colors.ink }} className="text-sm font-semibold">Artículos publicados</span>
          <div className="flex items-center border rounded-full p-0.5" style={{ borderColor: cfg.colors.line }}>
            {["civil", "military"].map((key) => {
              const opt = trackInfo(key);
              return (
                <button key={key} onClick={() => setFilterTrack(key)} className="px-2.5 py-1 rounded-full text-[11px] font-semibold" style={{ ...sans, backgroundColor: filterTrack === key ? opt.accent : "transparent", color: filterTrack === key ? cfg.colors.card : "#5B6472" }}>
                  {opt.label}
                </button>
              );
            })}
          </div>
        </div>
        <ul className="space-y-2 max-h-[70vh] overflow-y-auto pr-1">
          {[...filteredList].sort((a, b) => new Date(b.dateAdded) - new Date(a.dateAdded)).map((a) => (
            <li key={a.id} className="flex items-center justify-between gap-2 p-3 border text-sm" style={{ borderColor: cfg.colors.line, backgroundColor: editingId === a.id ? mix(cfg.colors.ink, cfg.colors.card, 0.92) : cfg.colors.card }}>
              <div className="min-w-0">
                <div style={{ ...sans, color: cfg.colors.ink }} className="font-medium truncate">{a.title}</div>
                <div style={{ ...sans, color: "#5B6472" }} className="text-xs">{formatDate(a.dateAdded)}</div>
              </div>
              <div className="flex items-center gap-3 shrink-0">
                <button onClick={() => startEdit(a)} style={{ color: cfg.colors.ink }} title="Editar"><Pencil size={15} /></button>
                <button onClick={() => handleDelete(a.id)} style={{ color: cfg.colors.error }} title="Eliminar"><Trash2 size={16} /></button>
              </div>
            </li>
          ))}
          {filteredList.length === 0 && (
            <p style={{ ...sans, color: "#5B6472" }} className="text-sm italic">Todavía no hay artículos en esta área.</p>
          )}
        </ul>
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Admin — tab: Reseñas (testimonios mostrados a visitantes)           */
/* ------------------------------------------------------------------ */
function emptyReviewForm() {
  return { authorName: "", rating: 5, body: "" };
}

function ReviewsTab({ reviews, setReviews }) {
  const { cfg, sans, serif } = useTheme();
  const [form, setForm] = useState(emptyReviewForm());
  const [message, setMessage] = useState("");

  function updateField(field, value) {
    setForm((f) => ({ ...f, [field]: value }));
  }

  async function handleSubmit(e) {
    e.preventDefault();
    if (!form.authorName.trim() || !form.body.trim()) {
      setMessage("Añade el nombre de quien la escribió y el texto de la reseña.");
      return;
    }
    try {
      const created = await api.insertReview({ authorName: form.authorName.trim(), rating: Number(form.rating), body: form.body.trim() });
      setReviews((prev) => [created, ...prev]);
      setMessage("Reseña publicada.");
    } catch {
      setMessage("No se pudo guardar. Inténtalo de nuevo.");
    }
    setForm(emptyReviewForm());
  }

  async function handleDelete(id) {
    try {
      await api.deleteReview(id);
      setReviews((prev) => prev.filter((r) => r.id !== id));
    } catch {
      setMessage("No se pudo eliminar. Inténtalo de nuevo.");
    }
  }

  return (
    <div className="grid lg:grid-cols-[1fr_1fr] gap-10">
      <div>
        <p style={{ ...sans, color: "#5B6472" }} className="text-sm mb-6">
          Copia aquí las reseñas que te dejen tus alumnos (en Google o donde sea). Se muestran a cualquier visitante, incluso antes de
          registrarse.
        </p>
        <form onSubmit={handleSubmit} className="space-y-4">
          <label className="text-sm block" style={sans}>
            Nombre de quien la escribió
            <input value={form.authorName} onChange={(e) => updateField("authorName", e.target.value)} className="mt-1 w-full border px-3 py-2" style={{ borderColor: cfg.colors.line }} placeholder="Ej. María G." />
          </label>
          <label className="text-sm block" style={sans}>
            Puntuación
            <select value={form.rating} onChange={(e) => updateField("rating", e.target.value)} className="mt-1 w-full border px-3 py-2" style={{ borderColor: cfg.colors.line }}>
              {[5, 4, 3, 2, 1].map((n) => <option key={n} value={n}>{"★".repeat(n)} ({n})</option>)}
            </select>
          </label>
          <label className="text-sm block" style={sans}>
            Texto de la reseña
            <textarea value={form.body} onChange={(e) => updateField("body", e.target.value)} rows={4} className="mt-1 w-full border px-3 py-2" style={{ borderColor: cfg.colors.line }} />
          </label>
          <div className="flex items-center gap-3">
            <button type="submit" className="px-5 py-2.5 text-sm font-semibold rounded-sm" style={{ ...sans, backgroundColor: cfg.colors.ink, color: cfg.colors.bg }}>
              Publicar reseña
            </button>
            {message && <span style={{ ...sans, color: "#5B6472" }} className="text-xs">{message}</span>}
          </div>
        </form>
      </div>

      <div>
        <span style={{ ...sans, color: cfg.colors.ink }} className="text-sm font-semibold">Reseñas publicadas</span>
        <ul className="space-y-2 mt-3 max-h-[70vh] overflow-y-auto pr-1">
          {reviews.map((r) => (
            <li key={r.id} className="flex items-start justify-between gap-2 p-3 border text-sm" style={{ borderColor: cfg.colors.line, backgroundColor: cfg.colors.card }}>
              <div className="min-w-0">
                <div style={{ ...sans, color: "#D4A017" }} className="text-xs">{"★".repeat(r.rating)}</div>
                <div style={{ ...sans, color: cfg.colors.ink }} className="font-medium">{r.authorName}</div>
                <div style={{ ...sans, color: "#5B6472" }} className="text-xs line-clamp-2">{r.body}</div>
              </div>
              <button onClick={() => handleDelete(r.id)} style={{ color: cfg.colors.error }} title="Eliminar" className="shrink-0"><Trash2 size={16} /></button>
            </li>
          ))}
          {reviews.length === 0 && (
            <p style={{ ...sans, color: "#5B6472" }} className="text-sm italic">Todavía no hay reseñas publicadas.</p>
          )}
        </ul>
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Admin — tab: Recursos (teoría y documentos descargables)            */
/* ------------------------------------------------------------------ */
function emptyMaterialForm(track = "civil") {
  return { track, category: "grammar", kind: "theory", title: "", body: "", fileUrl: "", fileName: "" };
}

function MaterialsTab({ materials, setMaterials, track }) {
  const { cfg, sans, trackInfo } = useTheme();
  const [form, setForm] = useState(emptyMaterialForm(track));
  const [message, setMessage] = useState("");
  const [filterTrack, setFilterTrack] = useState(track);

  function updateField(field, value) {
    setForm((f) => ({ ...f, [field]: value }));
  }

  async function handleSubmit(e) {
    e.preventDefault();
    if (!form.title.trim()) {
      setMessage("Añade un título.");
      return;
    }
    if (form.kind === "theory" && !form.body.trim()) {
      setMessage("Escribe el texto de la explicación teórica.");
      return;
    }
    if (form.kind === "file" && !form.fileUrl.trim()) {
      setMessage("Pega el enlace o el base64 del documento.");
      return;
    }
    const newMaterial = {
      track: form.track,
      category: form.category,
      kind: form.kind,
      title: form.title.trim(),
      body: form.body.trim(),
      fileUrl: form.fileUrl.trim(),
      fileName: form.fileName.trim(),
    };
    try {
      const created = await api.insertMaterial(newMaterial);
      setMaterials((prev) => [created, ...prev]);
      setMessage("Publicado correctamente.");
    } catch {
      setMessage("No se pudo guardar. Inténtalo de nuevo.");
    }
    setForm(emptyMaterialForm(form.track));
  }

  async function handleDelete(id) {
    try {
      await api.deleteMaterial(id);
      setMaterials((prev) => prev.filter((m) => m.id !== id));
    } catch {
      setMessage("No se pudo eliminar. Inténtalo de nuevo.");
    }
  }

  const filteredList = materials.filter((m) => m.track === filterTrack);

  return (
    <div className="grid lg:grid-cols-[1.1fr_0.9fr] gap-10">
      <div>
        <p style={{ ...sans, color: "#5B6472" }} className="text-sm mb-2">
          Añade explicaciones teóricas o documentos descargables (Word, PDF, lo que sea) a la sección de cada categoría. Los alumnos los
          verán al entrar en Gramática, Listening, Reading o Writing, antes de la lista de ejercicios.
        </p>
        <p style={{ ...sans, color: "#5B6472" }} className="text-xs mb-6 flex items-start gap-1.5">
          <FileText size={13} className="mt-0.5 shrink-0" />
          Para documentos: como esta plantilla no permite subir archivos directamente, pega un enlace a un archivo ya alojado en algún
          sitio, o el propio archivo convertido a base64 (igual que con las imágenes). El alumno lo descarga con un clic.
        </p>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="grid sm:grid-cols-3 gap-3">
            <label className="text-sm" style={sans}>
              Área
              <select value={form.track} onChange={(e) => updateField("track", e.target.value)} className="mt-1 w-full border px-3 py-2" style={{ borderColor: cfg.colors.line }}>
                <option value="civil">{cfg.copy.civil.label}</option>
                <option value="military">{cfg.copy.military.label}</option>
              </select>
            </label>
            <label className="text-sm" style={sans}>
              Categoría
              <select value={form.category} onChange={(e) => updateField("category", e.target.value)} className="mt-1 w-full border px-3 py-2" style={{ borderColor: cfg.colors.line }}>
                {CATEGORY_KEYS.map((key) => <option key={key} value={key}>{cfg.categoryLabels[key]}</option>)}
              </select>
            </label>
            <label className="text-sm" style={sans}>
              Tipo
              <select value={form.kind} onChange={(e) => updateField("kind", e.target.value)} className="mt-1 w-full border px-3 py-2" style={{ borderColor: cfg.colors.line }}>
                <option value="theory">Explicación teórica</option>
                <option value="file">Documento descargable</option>
              </select>
            </label>
          </div>

          <label className="text-sm block" style={sans}>
            Título
            <input value={form.title} onChange={(e) => updateField("title", e.target.value)} className="mt-1 w-full border px-3 py-2" style={{ borderColor: cfg.colors.line }} placeholder={form.kind === "theory" ? "Ej. Cómo usar los conectores" : "Ej. Plantilla de vocabulario — Unidad 3"} />
          </label>

          {form.kind === "theory" ? (
            <label className="text-sm block" style={sans}>
              Texto de la explicación
              <textarea value={form.body} onChange={(e) => updateField("body", e.target.value)} rows={6} className="mt-1 w-full border px-3 py-2" style={{ borderColor: cfg.colors.line }} />
            </label>
          ) : (
            <>
              <label className="text-sm block" style={sans}>
                Enlace o base64 del documento
                <textarea value={form.fileUrl} onChange={(e) => updateField("fileUrl", e.target.value)} rows={3} placeholder="https://… o data:application/vnd.openxmlformats-officedocument.wordprocessingml.document;base64,…" className="mt-1 w-full border px-3 py-2 text-xs font-mono" style={{ borderColor: cfg.colors.line }} />
              </label>
              <label className="text-sm block" style={sans}>
                Nombre del archivo al descargar (opcional)
                <input value={form.fileName} onChange={(e) => updateField("fileName", e.target.value)} placeholder="unidad-3-vocabulario.docx" className="mt-1 w-full border px-3 py-2" style={{ borderColor: cfg.colors.line }} />
              </label>
            </>
          )}

          <div className="flex items-center gap-3">
            <button type="submit" className="px-5 py-2.5 text-sm font-semibold rounded-sm" style={{ ...sans, backgroundColor: cfg.colors.ink, color: cfg.colors.bg }}>
              Publicar
            </button>
            {message && <span style={{ ...sans, color: "#5B6472" }} className="text-xs">{message}</span>}
          </div>
        </form>
      </div>

      <div>
        <div className="flex items-center justify-between mb-3">
          <span style={{ ...sans, color: cfg.colors.ink }} className="text-sm font-semibold">Publicado</span>
          <div className="flex items-center border rounded-full p-0.5" style={{ borderColor: cfg.colors.line }}>
            {["civil", "military"].map((key) => {
              const opt = trackInfo(key);
              return (
                <button key={key} onClick={() => setFilterTrack(key)} className="px-2.5 py-1 rounded-full text-[11px] font-semibold" style={{ ...sans, backgroundColor: filterTrack === key ? opt.accent : "transparent", color: filterTrack === key ? cfg.colors.card : "#5B6472" }}>
                  {opt.label}
                </button>
              );
            })}
          </div>
        </div>
        <ul className="space-y-2 max-h-[70vh] overflow-y-auto pr-1">
          {[...filteredList].sort((a, b) => new Date(b.dateAdded) - new Date(a.dateAdded)).map((m) => (
            <li key={m.id} className="flex items-center justify-between gap-2 p-3 border text-sm" style={{ borderColor: cfg.colors.line, backgroundColor: cfg.colors.card }}>
              <div className="min-w-0">
                <div style={{ ...sans, color: cfg.colors.ink }} className="font-medium truncate">{m.title}</div>
                <div style={{ ...sans, color: "#5B6472" }} className="text-xs">
                  {cfg.categoryLabels[m.category]} · {m.kind === "theory" ? "Teoría" : "Descarga"} · {formatDate(m.dateAdded)}
                </div>
              </div>
              <button onClick={() => handleDelete(m.id)} style={{ color: cfg.colors.error }} title="Eliminar"><Trash2 size={16} /></button>
            </li>
          ))}
          {filteredList.length === 0 && (
            <p style={{ ...sans, color: "#5B6472" }} className="text-sm italic">Todavía no hay recursos en esta área.</p>
          )}
        </ul>
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Admin — tab: Diseño de portada (orden y visibilidad de bloques)     */
/* ------------------------------------------------------------------ */
const BLOCK_LABELS = { intro: "Portada y boletín del día", categories: "Tarjetas de categorías", articles: "Artículos destacados" };

function LayoutTab({ cfg, updateConfig }) {
  const { sans, serif } = useTheme();
  const layout = cfg.homeLayout;

  function move(index, dir) {
    const next = [...layout];
    const target = index + dir;
    if (target < 0 || target >= next.length) return;
    [next[index], next[target]] = [next[target], next[index]];
    updateConfig({ homeLayout: next });
  }

  function toggleVisible(key) {
    updateConfig({ homeVisibility: { ...cfg.homeVisibility, [key]: !cfg.homeVisibility[key] } });
  }

  function updateContentSize(key, value) {
    updateConfig({ contentSizes: { ...cfg.contentSizes, [key]: value } });
  }

  return (
    <div className="max-w-xl space-y-8">
      <div>
        <h4 style={{ ...serif, color: cfg.colors.ink }} className="text-base font-semibold mb-1">
          Orden de la página de inicio
        </h4>
        <p style={{ ...sans, color: "#5B6472" }} className="text-sm mb-4">
          Cambia el orden de los bloques con las flechas, o desactívalos si no quieres que aparezcan.
        </p>
        <div className="space-y-2">
          {layout.map((key, i) => (
            <div key={key} className="flex items-center justify-between gap-3 p-3 border" style={{ borderColor: cfg.colors.line, opacity: cfg.homeVisibility[key] ? 1 : 0.5 }}>
              <span style={{ ...sans, color: cfg.colors.ink }} className="text-sm font-medium">{BLOCK_LABELS[key]}</span>
              <div className="flex items-center gap-2">
                <button type="button" onClick={() => move(i, -1)} disabled={i === 0} className="p-1.5 border rounded-sm disabled:opacity-30" style={{ borderColor: cfg.colors.line }}>
                  <ArrowUp size={14} />
                </button>
                <button type="button" onClick={() => move(i, 1)} disabled={i === layout.length - 1} className="p-1.5 border rounded-sm disabled:opacity-30" style={{ borderColor: cfg.colors.line }}>
                  <ArrowDown size={14} />
                </button>
                <label className="flex items-center gap-1.5 text-xs ml-2" style={sans}>
                  <input type="checkbox" checked={cfg.homeVisibility[key]} onChange={() => toggleVisible(key)} />
                  Visible
                </label>
              </div>
            </div>
          ))}
        </div>
      </div>

      <div>
        <h4 style={{ ...serif, color: cfg.colors.ink }} className="text-base font-semibold mb-1">
          Tamaño de las imágenes
        </h4>
        <p style={{ ...sans, color: "#5B6472" }} className="text-sm mb-3">
          Ajusta la altura de las imágenes que publicas en distintos sitios de la web.
        </p>
        <SizeControlRow
          label="Banner de cabecera (Civil / Militar)"
          size={cfg.contentSizes.banner}
          onSizeChange={(v) => updateContentSize("banner", v)}
          min={80}
          max={480}
          colors={cfg.colors}
          sans={sans}
        />
        <SizeControlRow
          label="Portada de artículo (en tarjetas)"
          size={cfg.contentSizes.articleCardCover}
          onSizeChange={(v) => updateContentSize("articleCardCover", v)}
          min={60}
          max={320}
          colors={cfg.colors}
          sans={sans}
        />
        <SizeControlRow
          label="Portada de artículo (artículo completo)"
          size={cfg.contentSizes.articleDetailCover}
          onSizeChange={(v) => updateContentSize("articleDetailCover", v)}
          min={100}
          max={600}
          colors={cfg.colors}
          sans={sans}
        />
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Admin — tab: Avanzado (restablecer, y límites honestos)             */
/* ------------------------------------------------------------------ */
function AdvancedTab({ cfg, onReset }) {
  const { sans, serif } = useTheme();
  const [confirming, setConfirming] = useState(false);
  const [done, setDone] = useState(false);

  async function handleReset() {
    await onReset();
    setDone(true);
    setConfirming(false);
  }

  return (
    <div className="max-w-xl space-y-6">
      <div>
        <h4 style={{ ...serif, color: cfg.colors.ink }} className="text-base font-semibold mb-2 flex items-center gap-2">
          <RotateCcw size={16} /> Restablecer diseño y textos
        </h4>
        <p style={{ ...sans, color: "#5B6472" }} className="text-sm mb-3">
          Si un cambio de color, fuente u orden de bloques deja la página en un estado que no te gusta, puedes volver a los valores
          originales de diseño. Esto no borra tus ejercicios ni tus artículos, solo colores, fuentes, iconos, textos de portada y el orden
          de los bloques.
        </p>
        {!confirming && !done && (
          <button onClick={() => setConfirming(true)} className="px-4 py-2 text-sm font-semibold rounded-sm border" style={{ ...sans, borderColor: cfg.colors.error, color: cfg.colors.error }}>
            Restablecer diseño a los valores originales
          </button>
        )}
        {confirming && (
          <div className="p-3 border space-y-2" style={{ borderColor: cfg.colors.error }}>
            <p style={{ ...sans, color: cfg.colors.ink }} className="text-sm">¿Seguro? Se perderán tus cambios de diseño y textos.</p>
            <div className="flex gap-2">
              <button onClick={handleReset} className="px-3 py-1.5 text-xs font-semibold rounded-sm" style={{ ...sans, backgroundColor: cfg.colors.error, color: "#fff" }}>
                Sí, restablecer
              </button>
              <button onClick={() => setConfirming(false)} className="px-3 py-1.5 text-xs font-semibold rounded-sm border" style={{ ...sans, borderColor: cfg.colors.line, color: cfg.colors.ink }}>
                Cancelar
              </button>
            </div>
          </div>
        )}
        {done && <p style={{ ...sans, color: cfg.colors.success }} className="text-sm">Hecho — diseño restablecido.</p>}
      </div>

      <div className="p-4 border flex items-start gap-3" style={{ borderColor: cfg.colors.line, backgroundColor: mix(cfg.colors.ink, "#ffffff", 0.94) }}>
        <AlertTriangle size={16} style={{ color: cfg.colors.ink, marginTop: 2 }} />
        <p style={{ ...sans, color: cfg.colors.ink }} className="text-sm">
          Este botón soluciona problemas de <em>diseño</em> (colores, fuentes, textos, orden). Si alguna vez la página deja de funcionar
          correctamente por un problema del propio código — no de configuración —, ese tipo de error no se puede arreglar desde aquí:
          vuelve a esta conversación con Claude, cuéntame qué ha pasado y lo corrijo directamente en el código.
        </p>
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Admin — root panel with tabs                                        */
/* ------------------------------------------------------------------ */
function AdminPanel({ exercises, setExercises, articles, setArticles, materials, setMaterials, reviews, setReviews, track, cfg, updateConfig, resetConfig, customLogo, onSetCustomLogo, onClearCustomLogo, profile }) {
  const { serif, sans } = useTheme();
  const [tab, setTab] = useState("content");
  const [users, setUsers] = useState([]);
  const [submissions, setSubmissions] = useState([]);

  useEffect(() => {
    (async () => {
      const [profiles, subs] = await Promise.all([api.fetchAllProfiles(), api.fetchSubmissions()]);
      setUsers(profiles);
      setSubmissions(subs);
    })();
  }, []);

  const pendingCount = users.filter((u) => u.status === "pending").length;
  const tabs = [
    { key: "content", label: "Ejercicios", icon: FileText },
    { key: "articles", label: "Artículos", icon: Newspaper },
    { key: "reviews", label: "Reseñas", icon: Star },
    { key: "materials", label: "Recursos", icon: FileText },
    { key: "students", label: pendingCount > 0 ? `Alumnos (${pendingCount})` : "Alumnos", icon: Users },
    { key: "progress", label: "Progreso", icon: TrendingUp },
    { key: "layout", label: "Diseño", icon: LayoutGrid },
    { key: "appearance", label: "Apariencia", icon: Palette },
    { key: "categories", label: "Categorías", icon: Smile },
    { key: "emojis", label: "Emojis", icon: Sparkles },
    { key: "texts", label: "Textos", icon: TypeIcon },
    { key: "access", label: "Acceso", icon: KeyRound },
    { key: "advanced", label: "Avanzado", icon: RotateCcw },
  ];

  return (
    <div className="max-w-6xl mx-auto px-6 py-12">
      <h2 style={{ ...serif, color: cfg.colors.ink }} className="text-2xl font-semibold mb-1">
        Panel de administración
      </h2>
      <p style={{ ...sans, color: "#5B6472" }} className="text-sm mb-6">
        Aquí controlas todo: ejercicios, artículos, imágenes, colores, fuentes, emojis, textos y el orden de los bloques de la portada.
      </p>

      <div className="flex flex-wrap gap-1 mb-8 border-b" style={{ borderColor: cfg.colors.line }}>
        {tabs.map((t) => {
          const Icon = t.icon;
          const active = tab === t.key;
          return (
            <button
              key={t.key}
              onClick={() => setTab(t.key)}
              className="flex items-center gap-1.5 px-4 py-2.5 text-sm font-medium border-b-2 -mb-px"
              style={{ ...sans, borderColor: active ? cfg.colors.ink : "transparent", color: active ? cfg.colors.ink : "#5B6472" }}
            >
              <Icon size={14} />
              {t.label}
            </button>
          );
        })}
      </div>

      {tab === "content" && <ContentTab exercises={exercises} setExercises={setExercises} track={track} />}
      {tab === "articles" && <ArticlesTab articles={articles} setArticles={setArticles} track={track} />}
      {tab === "reviews" && <ReviewsTab reviews={reviews} setReviews={setReviews} />}
      {tab === "materials" && <MaterialsTab materials={materials} setMaterials={setMaterials} track={track} />}
      {tab === "students" && <StudentsTab users={users} setUsers={setUsers} currentAdminId={profile?.id} />}
      {tab === "progress" && <ProgressTab users={users} submissions={submissions} />}
      {tab === "layout" && <LayoutTab cfg={cfg} updateConfig={updateConfig} />}
      {tab === "appearance" && <AppearanceTab cfg={cfg} updateConfig={updateConfig} customLogo={customLogo} onSetCustomLogo={onSetCustomLogo} onClearCustomLogo={onClearCustomLogo} />}
      {tab === "categories" && <CategoriesTab cfg={cfg} updateConfig={updateConfig} />}
      {tab === "emojis" && <EmojisTab cfg={cfg} updateConfig={updateConfig} />}
      {tab === "texts" && <TextsTab cfg={cfg} updateConfig={updateConfig} />}
      {tab === "access" && <AccessTab profile={profile} />}
      {tab === "advanced" && <AdvancedTab cfg={cfg} onReset={resetConfig} />}
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Error boundary — keeps a broken block from taking down the whole   */
/*  page, and gives a safe way back.                                   */
/* ------------------------------------------------------------------ */
class ErrorBoundary extends Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false };
  }
  static getDerivedStateFromError() {
    return { hasError: true };
  }
  componentDidCatch(error, info) {
    console.error("Sterling/I may app error:", error, info);
  }
  render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-[50vh] flex items-center justify-center px-6">
          <div className="max-w-sm text-center">
            <AlertTriangle size={22} className="mx-auto mb-3" style={{ color: "#A23B2E" }} />
            <p className="text-sm mb-4" style={{ color: "#16233F" }}>
              Algo ha fallado al mostrar esta sección. Puedes volver al inicio o restablecer el diseño desde el panel de administración
              (pestaña "Avanzado").
            </p>
            <button
              onClick={() => this.props.onRecover?.()}
              className="px-4 py-2 text-sm font-semibold rounded-sm"
              style={{ backgroundColor: "#16233F", color: "#F7F4EC" }}
            >
              Volver al inicio
            </button>
          </div>
        </div>
      );
    }
    return this.props.children;
  }
}

/* ------------------------------------------------------------------ */
/*  Root                                                                */
/* ------------------------------------------------------------------ */
export default function App() {
  useAcademyFonts();
  const [exercises, setExercises] = useState(null);
  const [articles, setArticles] = useState(null);
  const [materials, setMaterials] = useState(null);
  const [reviews, setReviews] = useState([]);
  const [submissions, setSubmissions] = useState([]);
  const [profile, setProfile] = useState(null);
  const [authReady, setAuthReady] = useState(false);
  const [recoveryMode, setRecoveryMode] = useState(false);
  const [cfg, setCfg] = useState(DEFAULT_CONFIG);
  const [customLogo, setCustomLogo] = useState(null);
  const [view, setView] = useState({ name: "home" });
  const [track, setTrackState] = useState("civil");
  const [boundaryKey, setBoundaryKey] = useState(0);

  useEffect(() => {
    (async () => {
      const [loadedExercises, loadedArticles, loadedMaterials, loadedReviews, siteConfig] = await Promise.all([
        api.fetchExercises(),
        api.fetchArticles(),
        api.fetchMaterials(),
        api.fetchReviews(),
        api.fetchSiteConfig(),
      ]);
      setExercises(loadedExercises);
      setArticles(loadedArticles);
      setMaterials(loadedMaterials);
      setReviews(loadedReviews);
      setCfg(mergeConfig(siteConfig.config));
      setCustomLogo(siteConfig.customLogo);
      const preferredTrack = api.getPreferredTrack();
      if (preferredTrack === "civil" || preferredTrack === "military") setTrackState(preferredTrack);
    })();
  }, []);

  useEffect(() => {
    const { data: subscription } = supabase.auth.onAuthStateChange(async (_event, session) => {
      if (_event === "PASSWORD_RECOVERY") setRecoveryMode(true);
      if (!session) {
        setProfile(null);
        setSubmissions([]);
        setAuthReady(true);
        return;
      }
      try {
        const p = await api.fetchMyProfile();
        setProfile(p);
        if (p && p.status === "approved") {
          setSubmissions(await api.fetchSubmissions());
        }
      } finally {
        setAuthReady(true);
      }
    });
    return () => subscription.subscription.unsubscribe();
  }, []);

  const setTrack = useCallback((next) => {
    setTrackState(next);
    setView({ name: "home" });
    api.setPreferredTrack(next);
  }, []);

  const recordSubmission = useCallback((entry) => {
    setSubmissions((prev) => {
      const filtered = prev.filter((s) => !(s.userId === entry.userId && s.exerciseId === entry.exerciseId));
      return [...filtered, entry];
    });
    api.upsertSubmission({ userId: entry.userId, exerciseId: entry.exerciseId, score: entry.score, total: entry.total });
  }, []);

  const handleLogout = useCallback(async () => {
    await api.signOut();
    setView({ name: "home" });
  }, []);

  const updateConfig = useCallback((partial) => {
    setCfg((prev) => {
      const next = mergeConfig({ ...prev, ...partial });
      api.saveSiteConfig(next);
      return next;
    });
  }, []);

  const resetConfig = useCallback(async () => {
    setCfg(DEFAULT_CONFIG);
    await api.saveSiteConfig(DEFAULT_CONFIG);
  }, []);

  const setCustomLogoPersisted = useCallback(async (value) => {
    try {
      await api.saveCustomLogo(value);
      setCustomLogo(value);
      return true;
    } catch {
      return false;
    }
  }, []);

  const clearCustomLogo = useCallback(async () => {
    await api.clearCustomLogo();
    setCustomLogo(null);
  }, []);

  const recoverFromError = useCallback(() => {
    setView({ name: "home" });
    setBoundaryKey((k) => k + 1);
  }, []);

  const theme = useMemo(() => ({ ...buildTheme(cfg, track), logoSrc: customLogo || LOGO_SRC }), [cfg, customLogo, track]);

  const currentUser = profile;

  if (exercises === null || articles === null || materials === null || !authReady) {
    return (
      <div className="min-h-screen flex items-center justify-center" style={{ backgroundColor: cfg.colors.bg }}>
        <img src={customLogo || LOGO_SRC} alt={cfg.siteName} className="h-14 w-auto opacity-80" />
      </div>
    );
  }

  if (recoveryMode) {
    return (
      <ThemeContext.Provider value={theme}>
        <div className="min-h-screen" style={{ backgroundColor: cfg.colors.bg, ...theme.sans }}>
          <PasswordRecoveryScreen onDone={() => setRecoveryMode(false)} />
        </div>
      </ThemeContext.Provider>
    );
  }

  let content;
  if (view.name === "home") {
    content =
      profile && profile.status === "approved" ? (
        <Home exercises={exercises} articles={articles} setView={setView} track={track} />
      ) : (
        <PublicHome articles={articles} reviews={reviews} setView={setView} track={track} />
      );
  } else if (CATEGORY_KEYS.includes(view.name)) {
    content = <CategoryList type={view.name} exercises={exercises} materials={materials} setView={setView} focusId={view.focusId} track={track} submissions={submissions} currentUser={currentUser} />;
  } else if (view.name === "detail") {
    const exercise = exercises.find((e) => e.id === view.id);
    const priorSubmission = currentUser
      ? submissions.find((s) => s.userId === currentUser.id && s.exerciseId === view.id)
      : null;
    content = exercise ? (
      <ExerciseDetail
        exercise={exercise}
        setView={setView}
        track={track}
        currentUser={currentUser}
        priorSubmission={priorSubmission}
        onRecordSubmission={recordSubmission}
      />
    ) : (
      <div className="max-w-3xl mx-auto px-6 py-12">Ejercicio no encontrado.</div>
    );
  } else if (view.name === "temario") {
    content = <TemarioView materials={materials} track={track} setView={setView} />;
  } else if (view.name === "articles") {
    content = <ArticlesList articles={articles} track={track} setView={setView} />;
  } else if (view.name === "article-detail") {
    const article = articles.find((a) => a.id === view.id);
    content = article ? (
      <ArticleDetail article={article} setView={setView} />
    ) : (
      <div className="max-w-3xl mx-auto px-6 py-12">Artículo no encontrado.</div>
    );
  } else if (view.name === "admin") {
    content = (
      <AdminGate profile={profile} onLogout={handleLogout}>
        <AdminPanel
          exercises={exercises}
          setExercises={setExercises}
          articles={articles}
          setArticles={setArticles}
          materials={materials}
          setMaterials={setMaterials}
          reviews={reviews}
          setReviews={setReviews}
          track={track}
          cfg={cfg}
          updateConfig={updateConfig}
          resetConfig={resetConfig}
          customLogo={customLogo}
          onSetCustomLogo={setCustomLogoPersisted}
          onClearCustomLogo={clearCustomLogo}
          profile={profile}
        />
      </AdminGate>
    );
  }

  const PUBLIC_VIEWS = ["home", "articles", "article-detail"];
  const gatedContent =
    view.name === "admin" || PUBLIC_VIEWS.includes(view.name) ? (
      content
    ) : (
      <StudentAuthGate profile={profile} onLogout={handleLogout}>
        {content}
      </StudentAuthGate>
    );

  return (
    <ThemeContext.Provider value={theme}>
      <div className="min-h-screen" style={{ backgroundColor: cfg.colors.bg, ...theme.sans }}>
        <Navbar view={view} setView={setView} track={track} setTrack={setTrack} />
        <ErrorBoundary key={boundaryKey} onRecover={recoverFromError}>
          {gatedContent}
        </ErrorBoundary>
        <footer className="border-t mt-10 py-8" style={{ borderColor: cfg.colors.line }}>
          <div className="max-w-6xl mx-auto px-6 flex flex-col sm:flex-row items-center justify-between gap-3">
            <div className="flex items-center gap-3">
              {cfg.showLogoImage ? (
                <img src={theme.logoSrc} alt={cfg.siteName} style={{ height: cfg.logoLayout.footer.size }} className="w-auto" />
              ) : (
                <span style={{ ...theme.serif, color: cfg.colors.ink }} className="text-sm font-semibold">{cfg.siteName}</span>
              )}
              <div style={{ ...theme.sans, color: "#5B6472" }} className="text-xs">
                <div>© {new Date().getFullYear()} {cfg.siteName}</div>
                {cfg.copy.contactEmail || cfg.copy.contactPhone ? (
                  <div className="flex flex-wrap items-center gap-x-2">
                    <span className="font-semibold">Contacto:</span>
                    {cfg.copy.contactEmail && (
                      <a href={`mailto:${cfg.copy.contactEmail}`} className="underline" style={{ color: "#5B6472" }}>
                        {cfg.copy.contactEmail}
                      </a>
                    )}
                    {cfg.copy.contactEmail && cfg.copy.contactPhone && <span>·</span>}
                    {cfg.copy.contactPhone && (
                      <a href={`tel:${cfg.copy.contactPhone.replace(/\s+/g, "")}`} className="underline" style={{ color: "#5B6472" }}>
                        {cfg.copy.contactPhone}
                      </a>
                    )}
                  </div>
                ) : (
                  <span>— {cfg.copy.footerText}</span>
                )}
              </div>
            </div>
            <button onClick={() => setView({ name: "admin" })} className="text-xs underline" style={{ ...theme.sans, color: "#5B6472" }}>
              Panel de administración
            </button>
          </div>
        </footer>
      </div>
    </ThemeContext.Provider>
  );
}
